#include <stdio.h>
#include <stdlib.h>
typedef struct Node {
    int data;
    struct Node* next;
} Node;
Node* createNode(int data) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}
Node* reverse(Node* head) {
    Node* prev = NULL;
    Node* curr = head;
    Node* next = NULL;
    while (curr != NULL) {
        next = curr->next;
        curr->next = prev;
        prev = curr;
        curr = next;
    }
    return prev;
}
Node* addOne(Node* head) {
    head = reverse(head);
    Node* curr = head;
    Node* prev = NULL;
    int carry = 1;
    while (curr != NULL) {
        int sum = curr->data + carry;
        curr->data = sum % 10;
        carry = sum / 10;
        prev = curr;
        curr = curr->next;
    }
    if (carry > 0) {
        Node* newNode = createNode(carry);
        prev->next = newNode;
    }
    head = reverse(head);
    return head;
}
int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        Node* head = NULL;
        Node* tail = NULL;
        for (int i = 0; i < N; i++) {
            int data;
